// src/Profile.jsx
import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Profile() {
  const navigate = useNavigate();

  const menuButtonStyle = {
    minHeight: 80,
    background: "#ffffff",
    borderRadius: 16,
    boxShadow: "0 3px 14px rgba(0,0,0,0.1)",
    border: `2px solid ${lightGreen}`,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: 600,
    fontSize: 18,
    color: green,
    cursor: "pointer",
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 420,
          background: "#ffffff",
          borderRadius: 20,
          padding: 20,
          boxShadow: "0 8px 24px rgba(0,0,0,0.15)",
        }}
      >
        {/* ⭐ NEW — Back Arrow + Title */}
        <div style={{ display: "flex", alignItems: "center", marginBottom: 16 }}>
          <button
            onClick={() => navigate("/home")}
            style={{
              background: "none",
              border: "none",
              color: green,
              fontSize: 18,
              cursor: "pointer",
              marginRight: 8,
            }}
          >
            ⬅
          </button>

          <h2 style={{ color: green, margin: 0, fontSize: 20 }}>Profile</h2>
        </div>

        {/* MENU BUTTONS */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(2,1fr)",
            gap: 14,
          }}
        >
          <button style={menuButtonStyle} onClick={() => navigate("/dashboard")}>
            Dashboard
          </button>
          <button style={menuButtonStyle} onClick={() => navigate("/addnew")}>
            Add New
          </button>
          <button style={menuButtonStyle} onClick={() => navigate("/history")}>
            History
          </button>
          <button style={menuButtonStyle} onClick={() => navigate("/tools")}>
            Tools
          </button>
        </div>
      </div>
    </div>
  );
}
